config.script:
function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function pageText(){var t=(document.title||'').toLowerCase();var b=(document.body?document.body.innerText:'')||'';return t+' '+b.toLowerCase();}
function networkErr(){var s=pageText();return s.includes("this site can't be reached")||s.includes("this site can’t be reached")||s.includes('err_connection')||s.includes('err_tunnel')||s.includes('err_proxy')||s.includes('dns_probe_finished')||s.includes('check if there is a typo');}
function challenge(){var b=((document.body?document.body.innerText:'')||'').toLowerCase();return b.includes('robot or human?')||b.includes("activate and hold the button to confirm that you're human")||b.includes('activate and hold the button to confirm that you’re human');}
function emailReady(){var sels=['form#sign-in-form input[aria-label="Phone number or email"]','input[name="emailAddress"]','input[type="email"]','input[autocomplete="username"]'];for(var i=0;i<sels.length;i++){var el=document.querySelector(sels[i]);if(el){var r=el.getBoundingClientRect();var st=getComputedStyle(el);if(r.width>0&&r.height>0&&st.visibility!=='hidden'&&st.display!=='none')return true;}}return false;}
var start=Date.now();
while(document.readyState!=='complete'&&Date.now()-start<45000){await sleep(200);}
var deadline=Date.now()+20000;
while(Date.now()<deadline){
  if(networkErr()) throw new Error('Walmart unreachable (proxy/network) - rotate proxy.');
  if(challenge()) throw new Error('Walmart anti-bot challenge (Robot or human?) - proxy IP flagged, rotate proxy.');
  if(emailReady()) return (document.title||'').trim();
  await sleep(500);
}
if(challenge()) throw new Error('Walmart anti-bot challenge (Robot or human?) - proxy IP flagged, rotate proxy.');
return (document.title||'').trim();

function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
function state(){
  var fn=['input[name="firstName"]','input[autocomplete="given-name"]','input[aria-label="First name"]'];
  for(var i=0;i<fn.length;i++){if(vis(document.querySelector(fn[i])))return 'signup';}
  var body=String(document.body?document.body.innerText:'').toLowerCase();
  var choiceRoot=document.querySelector('[data-testid="identity-generic-choice-options"]');
  if(choiceRoot&&vis(choiceRoot)&&body.includes('choose a sign in method'))return 'existing';
  var pw=Array.from(document.querySelectorAll('#sign-in-password-no-otp, input[name="password"], form#sign-in-form input[type="password"]')).find(function(el){return vis(el)&&el.getAttribute('name')!=='newPassword';});
  if(pw&&(body.includes('enter your password')||body.includes('welcome back')||body.includes('sign in')))return 'existing';
  return '';
}
var start=Date.now();
while(document.readyState!=='complete'&&Date.now()-start<20000){await sleep(200);}
var deadline=Date.now()+30000;
var s='';
while(Date.now()<deadline){s=state();if(s)break;await sleep(250);}
if(s==='existing') throw new Error('Walmart account already exists for this email - marking email as used.');
if(s!=='signup') throw new Error('Email step did not resolve to signup details.');
return 'signup';

function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
var deadline=Date.now()+20000;
var opts=[];
while(Date.now()<deadline){
  opts=Array.from(document.querySelectorAll('[role="dialog"] li[data-index]')).filter(function(el){return vis(el)&&String(el.textContent||'').trim();});
  if(opts.length)break;
  await sleep(250);
}
if(!opts.length) throw new Error('Country / region options not found.');
var pool=opts.slice(0,2);
var choice=pool[Math.floor(Math.random()*pool.length)];
choice.scrollIntoView({block:'center'});
var target=choice.querySelector('label[data-testid$="-radio-btn"]')||choice.querySelector('input[type="radio"]')||choice;
target.click();
await sleep(500);
var dialog=document.querySelector('[role="dialog"]');
var confirm=dialog?Array.from(dialog.querySelectorAll('button')).find(function(b){return /select country/i.test(String(b.textContent||''));}):null;
if(confirm)confirm.click();
await sleep(500);
return String(choice.textContent||'').trim();

try{
  var cb=Array.from(document.querySelectorAll('input[type="checkbox"]')).find(function(el){
    var lbl=el.labels?Array.from(el.labels).map(function(l){return l.innerText||'';}).join(' '):'';
    return (String(el.id||'')+' '+String(el.name||'')+' '+lbl).toLowerCase().includes('marketing');
  });
  if(cb&&cb.checked)cb.click();
  return cb?'marketing-unchecked':'no-marketing-checkbox';
}catch(e){return 'marketing-skip';}

function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
function snap(){var t=(document.title||'').toLowerCase();var b=String(document.body?document.body.innerText:'').toLowerCase();return {b:b,all:t+' '+b};}
function classify(){
  var s=snap();
  if(s.all.includes("this site can't be reached")||s.all.includes("this site can’t be reached")||s.all.includes('err_connection')||s.all.includes('err_tunnel')||s.all.includes('err_proxy')||s.all.includes('dns_probe_finished')||s.all.includes('check if there is a typo'))return 'network';
  if(s.b.includes('robot or human?')||s.b.includes("activate and hold the button to confirm that you're human")||s.b.includes('activate and hold the button to confirm that you’re human'))return 'challenge';
  if(s.b.includes("unfortunately, we can't create your account."))return 'creationFailed';
  var choiceRoot=document.querySelector('[data-testid="identity-generic-choice-options"]');
  if(choiceRoot&&vis(choiceRoot)&&s.b.includes('choose a sign in method'))return 'existing';
  var pw=Array.from(document.querySelectorAll('#sign-in-password-no-otp, input[name="password"], form#sign-in-form input[type="password"]')).find(function(el){return vis(el)&&el.getAttribute('name')!=='newPassword';});
  if(pw&&(s.b.includes('enter your password')||s.b.includes('welcome back')||s.b.includes('sign in')))return 'existing';
  if(/verify|six.?digit|code|one-time/i.test(s.b))return 'otp';
  var otp=Array.from(document.querySelectorAll('input')).filter(function(el){if(!vis(el))return false;var m=((el.name||'')+' '+(el.id||'')+' '+(el.placeholder||'')+' '+(el.autocomplete||'')).toLowerCase();return /otp|code/.test(m);});
  if(otp.length)return 'otp';
  return '';
}
var start=Date.now();
while(document.readyState!=='complete'&&Date.now()-start<45000){await sleep(200);}
var deadline=Date.now()+45000;
var st='';
while(Date.now()<deadline){st=classify();if(st)break;await sleep(300);}
if(st==='network') throw new Error('Walmart verification step unreachable - rotate proxy.');
if(st==='challenge') throw new Error('Walmart anti-bot challenge after submit - rotate proxy.');
if(st==='creationFailed') throw new Error("Walmart reported it can't create this account - rotate proxy and retry.");
if(st==='existing') throw new Error('Walmart account already exists for this email - marking email as used.');
if(st!=='otp') throw new Error('Timed out waiting for the verification (OTP) screen.');
return 'otp';

function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>0&&r.height>0&&s.visibility!=='hidden'&&s.display!=='none';}
function snap(){var t=(document.title||'').toLowerCase();var b=String(document.body?document.body.innerText:'').toLowerCase();return {b:b,all:t+' '+b};}
function classify(){
  var s=snap();
  if(s.all.includes("this site can't be reached")||s.all.includes("this site can’t be reached")||s.all.includes('err_connection')||s.all.includes('err_tunnel')||s.all.includes('err_proxy')||s.all.includes('dns_probe_finished')||s.all.includes('check if there is a typo'))return 'network';
  if(s.b.includes('robot or human?')||s.b.includes("activate and hold the button to confirm that you're human")||s.b.includes('activate and hold the button to confirm that you’re human'))return 'challenge';
  if(s.b.includes('something went wrong. please try again.'))return 'done';
  var otp=Array.from(document.querySelectorAll('input')).filter(function(el){if(!vis(el))return false;var m=((el.name||'')+' '+(el.id||'')+' '+(el.placeholder||'')+' '+(el.autocomplete||'')).toLowerCase();return /otp|code|one-time/.test(m)||el.maxLength===1;});
  if(/verify|six.?digit|enter code/i.test(s.b)||otp.length>0)return '';
  return 'done';
}
var deadline=Date.now()+20000;
var st='';
while(Date.now()<deadline){st=classify();if(st)break;await sleep(300);}
if(st==='network') throw new Error('Submitting verification failed: browser reached error page - rotate proxy.');
if(st==='challenge') throw new Error('Submitting verification failed: anti-bot challenge - rotate proxy.');
if(st!=='done') throw new Error('Verification did not complete (code may be wrong or expired).');
return 'done';
